import subprocess
import sys

def main():
    try:
        result = subprocess.run(
            ['curl', '-I', 'http://example.com'],
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode != 0:
            print("Error: Failed to connect.")
            sys.exit(1)

        output = result.stdout.lower()
        if 'connected to example.com' in output:
            print("DNS resolution successful: Connected to example.com found.")
            sys.exit(0)
        else:
            print("DNS resolution failed: No 'Connected to example.com' message.")
            sys.exit(1)
    except Exception as e:
        print(f"Exception occurred: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()

